const API_BASE = "http://localhost:5001/api/patient/copilot";

async function handleResponse(res) {
  const body = await res.json().catch(() => ({ detail: res.statusText }));
  if (!res.ok) {
    throw new Error(body.error || body.detail || `HTTP ${res.status}`);
  }
  return body;
}

export async function uploadFile(file) {
  const form = new FormData();
  form.append("file", file);
  const res = await fetch(`${API_BASE}/upload`, { method: "POST", body: form });
  return handleResponse(res);
}

export async function normalizeText(text, patientId) {
  const res = await fetch(`${API_BASE}/normalize`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text, patient_id: patientId }),
  });
  return handleResponse(res);
}

export async function analyzeChart(text, patientId) {
  const res = await fetch(`${API_BASE}/analyze`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ text, patient_id: patientId }),
  });
  return handleResponse(res);
}
